    /// <summary>
    /// javascript: URLs in href attributes are blocked and not included in output
    /// </summary>
    [Fact]
    public void TestXssJavascriptUrlBlocked()
    {
        var html = "<p><a href=\"javascript:alert('xss')\">Click me</a></p>";
        var result = HtmlToMarkdownConverter.Convert(html);
        var content = result.Content ?? "";

        Assert.False(string.IsNullOrWhiteSpace(content));
        Assert.Contains("Click me", content);
        Assert.DoesNotContain("javascript:", content);
        Assert.DoesNotContain("alert(", content);
    }

    /// <summary>
    /// onclick and other on* event handlers are removed from elements
    /// </summary>
    [Fact]
    public void TestXssOnclickHandlerRemoved()
    {
        var html = "<p><a href=\"https://example.com\" onclick=\"alert('xss')\">Click me</a></p><button onmouseover=\"steal_data()\">Hover me</button>";
        var result = HtmlToMarkdownConverter.Convert(html);
        var content = result.Content ?? "";

        Assert.False(string.IsNullOrWhiteSpace(content));
        Assert.Contains("Click me", content);
        Assert.DoesNotContain("onclick", content);
        Assert.DoesNotContain("onmouseover", content);
        Assert.DoesNotContain("alert(", content);
        Assert.DoesNotContain("steal_data", content);
    }

